import javafx.application.Application;
import javafx.beans.property.*;
import javafx.collections.FXCollections;
import javafx.collections.ObservableList;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Scene;
import javafx.scene.control.*;
import javafx.scene.layout.HBox;
import javafx.scene.layout.VBox;
import javafx.stage.Stage;

import java.time.LocalDate;
import java.time.format.DateTimeFormatter;

// Task model
class Task {
    private final StringProperty description;
    private final BooleanProperty completed;
    private final ObjectProperty<LocalDate> dueDate;

    Task(String description, LocalDate dueDate) {
        this.description = new SimpleStringProperty(description);
        this.completed = new SimpleBooleanProperty(false);
        this.dueDate = new SimpleObjectProperty<>(dueDate);
    }

    public String getDescription() { return description.get(); }
    public StringProperty descriptionProperty() { return description; }

    public boolean getCompleted() { return completed.get(); }
    public BooleanProperty completedProperty() { return completed; }

    public LocalDate getDueDate() { return dueDate.get(); }
    public ObjectProperty<LocalDate> dueDateProperty() { return dueDate; }

    @Override
    public String toString() {
        return description.get() + (completed.get() ? " ✓" : "") + 
               " (Due: " + dueDate.get().format(DateTimeFormatter.ISO_LOCAL_DATE) + ")";
    }
}

// Main To-Do List Application
public class TodoListApp extends Application {
    private ObservableList<Task> tasks;
    private ListView<Task> taskListView;
    private Label statusLabel;

    @Override
    public void start(Stage primaryStage) {
        tasks = FXCollections.observableArrayList();

        // Add some sample tasks
        tasks.add(new Task("Learn JavaFX", LocalDate.now().plusDays(5)));
        tasks.add(new Task("Build a project", LocalDate.now().plusDays(10)));
        tasks.add(new Task("Review code", LocalDate.now().plusDays(2)));

        VBox root = new VBox(15);
        root.setPadding(new Insets(20));
        root.setAlignment(Pos.CENTER);

        // Header
        Label header = new Label("📋 To-Do List");
        header.setStyle("-fx-font-size: 24px; -fx-font-weight: bold;");
        root.getChildren().add(header);

        // Input section
        HBox inputBox = new HBox(10);
        inputBox.setAlignment(Pos.CENTER);

        TextField descField = new TextField();
        descField.setPromptText("Enter task...");
        descField.setPrefWidth(250);

        DatePicker datePicker = new DatePicker(LocalDate.now());
        datePicker.setPrefWidth(150);

        Button addBtn = new Button("Add Task");
        addBtn.setStyle("-fx-background-color: #4CAF50; -fx-text-fill: white;");
        addBtn.setOnAction(e -> {
            String desc = descField.getText().trim();
            if (!desc.isEmpty()) {
                tasks.add(new Task(desc, datePicker.getValue()));
                descField.clear();
                statusLabel.setText("Task added!");
                updateTaskListView();
            }
        });

        // Enter key support
        descField.setOnAction(e -> addBtn.fire());

        inputBox.getChildren().addAll(descField, datePicker, addBtn);
        root.getChildren().add(inputBox);

        // Task list
        taskListView = new ListView<>();
        taskListView.setPrefHeight(300);
        taskListView.setPrefWidth(500);

        // Custom cell factory for tasks
        taskListView.setCellFactory(param -> new ListCell<Task>() {
            @Override
            protected void updateItem(Task task, boolean empty) {
                super.updateItem(task, empty);
                if (empty || task == null) {
                    setText(null);
                    setStyle("");
                } else {
                    setText(task.toString());
                    if (task.getCompleted()) {
                        setStyle("-fx-text-fill: #888; -fx-font-style: italic;");
                    } else {
                        setStyle("-fx-text-fill: #333;");
                    }
                }
            }
        });

        updateTaskListView();
        root.getChildren().add(taskListView);

        // Action buttons
        HBox actionBox = new HBox(10);
        actionBox.setAlignment(Pos.CENTER);

        Button completeBtn = new Button("✅ Mark Complete");
        completeBtn.setOnAction(e -> {
            Task selected = taskListView.getSelectionModel().getSelectedItem();
            if (selected != null) {
                selected.completedProperty().set(true);
                updateTaskListView();
                statusLabel.setText("Task completed!");
            } else {
                statusLabel.setText("Select a task first!");
            }
        });

        Button deleteBtn = new Button("🗑️ Delete");
        deleteBtn.setStyle("-fx-background-color: #e74c3c; -fx-text-fill: white;");
        deleteBtn.setOnAction(e -> {
            Task selected = taskListView.getSelectionModel().getSelectedItem();
            if (selected != null) {
                tasks.remove(selected);
                updateTaskListView();
                statusLabel.setText("Task deleted!");
            } else {
                statusLabel.setText("Select a task first!");
            }
        });

        Button clearBtn = new Button("🧹 Clear Completed");
        clearBtn.setOnAction(e -> {
            tasks.removeIf(Task::getCompleted);
            updateTaskListView();
            statusLabel.setText("Completed tasks cleared!");
        });

        actionBox.getChildren().addAll(completeBtn, deleteBtn, clearBtn);
        root.getChildren().add(actionBox);

        // Status
        statusLabel = new Label("Ready");
        statusLabel.setStyle("-fx-font-style: italic; -fx-text-fill: #666;");
        root.getChildren().add(statusLabel);

        // Stats
        Label statsLabel = new Label();
        statsLabel.textProperty().bind(
            javafx.beans.binding.Bindings.createStringBinding(() -> {
                int total = tasks.size();
                long completed = tasks.stream().filter(Task::getCompleted).count();
                return String.format("Total: %d | Completed: %d | Pending: %d", 
                    total, completed, total - completed);
            }, tasks)
        );
        root.getChildren().add(statsLabel);

        Scene scene = new Scene(root, 600, 650);

        primaryStage.setTitle("To-Do List App");
        primaryStage.setScene(scene);
        primaryStage.show();
    }

    private void updateTaskListView() {
        taskListView.setItems(tasks);
        taskListView.refresh();
    }

    public static void main(String[] args) {
        launch(args);
    }
}

// Alternative: Calculator Mini App
class CalculatorApp extends Application {
    private TextField display;
    private double num1 = 0;
    private String operator = "";
    private boolean startNewNumber = true;

    @Override
    public void start(Stage primaryStage) {
        VBox root = new VBox(10);
        root.setPadding(new Insets(20));
        root.setAlignment(Pos.CENTER);

        // Display
        display = new TextField("0");
        display.setEditable(false);
        display.setAlignment(Pos.CENTER_RIGHT);
        display.setStyle("-fx-font-size: 24px; -fx-padding: 10px;");
        display.setPrefWidth(300);
        root.getChildren().add(display);

        // Button grid
        javafx.scene.layout.GridPane grid = new javafx.scene.layout.GridPane();
        grid.setHgap(5);
        grid.setVgap(5);
        grid.setAlignment(Pos.CENTER);

        String[] buttons = {
            "7", "8", "9", "/",
            "4", "5", "6", "*",
            "1", "2", "3", "-",
            "0", ".", "=", "+"
        };

        for (int i = 0; i < buttons.length; i++) {
            Button btn = new Button(buttons[i]);
            btn.setPrefSize(60, 60);
            btn.setStyle("-fx-font-size: 18px;");

            // Special styling for operators
            if (buttons[i].matches("[+\\-*/=]")) {
                btn.setStyle("-fx-font-size: 18px; -fx-background-color: #f0ad4e; -fx-text-fill: white;");
            }

            int row = i / 4;
            int col = i % 4;
            grid.add(btn, col, row);

            btn.setOnAction(e -> handleButtonPress(buttons[i]));
        }

        // Clear button
        Button clearBtn = new Button("C");
        clearBtn.setPrefSize(60, 60);
        clearBtn.setStyle("-fx-font-size: 18px; -fx-background-color: #d9534f; -fx-text-fill: white;");
        clearBtn.setOnAction(e -> {
            display.setText("0");
            num1 = 0;
            operator = "";
            startNewNumber = true;
        });
        grid.add(clearBtn, 3, 4);

        root.getChildren().add(grid);

        Scene scene = new Scene(root, 300, 400);
        primaryStage.setTitle("Calculator");
        primaryStage.setScene(scene);
        primaryStage.show();
    }

    private void handleButtonPress(String value) {
        if (value.matches("[0-9.]")) {
            if (startNewNumber) {
                display.setText(value);
                startNewNumber = false;
            } else {
                display.setText(display.getText() + value);
            }
        } else if (value.matches("[+\\-*/]")) {
            num1 = Double.parseDouble(display.getText());
            operator = value;
            startNewNumber = true;
        } else if (value.equals("=")) {
            double num2 = Double.parseDouble(display.getText());
            double result = calculate(num1, num2, operator);
            display.setText(String.valueOf(result));
            startNewNumber = true;
        }
    }

    private double calculate(double a, double b, String op) {
        switch (op) {
            case "+": return a + b;
            case "-": return a - b;
            case "*": return a * b;
            case "/": return b != 0 ? a / b : 0;
            default: return b;
        }
    }
}

