import javafx.application.Application;
import javafx.beans.property.*;
import javafx.collections.FXCollections;
import javafx.collections.ObservableList;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Scene;
import javafx.scene.control.*;
import javafx.scene.control.cell.PropertyValueFactory;
import javafx.scene.layout.HBox;
import javafx.scene.layout.VBox;
import javafx.stage.Stage;

class Contact {
    private final StringProperty name;
    private final StringProperty phone;
    private final StringProperty email;

    Contact(String name, String phone, String email) {
        this.name = new SimpleStringProperty(name);
        this.phone = new SimpleStringProperty(phone);
        this.email = new SimpleStringProperty(email);
    }

    public String getName() { return name.get(); }
    public StringProperty nameProperty() { return name; }

    public String getPhone() { return phone.get(); }
    public StringProperty phoneProperty() { return phone; }

    public String getEmail() { return email.get(); }
    public StringProperty emailProperty() { return email; }
}

public class ContactManager extends Application {
    @Override
    public void start(Stage primaryStage) {
        VBox root = new VBox(15);
        root.setPadding(new Insets(20));
        root.setAlignment(Pos.CENTER);

        ObservableList<Contact> contacts = FXCollections.observableArrayList();

        // TableView
        TableView<Contact> table = new TableView<>();
        table.setPrefHeight(300);
        table.setPrefWidth(500);

        TableColumn<Contact, String> nameCol = new TableColumn<>("Name");
        nameCol.setCellValueFactory(new PropertyValueFactory<>("name"));
        nameCol.setPrefWidth(150);

        TableColumn<Contact, String> phoneCol = new TableColumn<>("Phone");
        phoneCol.setCellValueFactory(new PropertyValueFactory<>("phone"));
        phoneCol.setPrefWidth(150);

        TableColumn<Contact, String> emailCol = new TableColumn<>("Email");
        emailCol.setCellValueFactory(new PropertyValueFactory<>("email"));
        emailCol.setPrefWidth(200);

        table.getColumns().addAll(nameCol, phoneCol, emailCol);
        table.setItems(contacts);

        // Input fields
        HBox inputBox = new HBox(10);
        inputBox.setAlignment(Pos.CENTER);

        TextField nameField = new TextField();
        nameField.setPromptText("Name");
        nameField.setMaxWidth(120);

        TextField phoneField = new TextField();
        phoneField.setPromptText("Phone");
        phoneField.setMaxWidth(120);

        TextField emailField = new TextField();
        emailField.setPromptText("Email");
        emailField.setMaxWidth(150);

        Button addBtn = new Button("Add Contact");
        addBtn.setOnAction(e -> {
            String name = nameField.getText().trim();
            String phone = phoneField.getText().trim();
            String email = emailField.getText().trim();
            if (!name.isEmpty()) {
                contacts.add(new Contact(name, phone, email));
                nameField.clear();
                phoneField.clear();
                emailField.clear();
            }
        });

        Button deleteBtn = new Button("Delete Contact");
        deleteBtn.setOnAction(e -> {
            Contact selected = table.getSelectionModel().getSelectedItem();
            if (selected != null) {
                contacts.remove(selected);
            }
        });

        inputBox.getChildren().addAll(nameField, phoneField, emailField, addBtn, deleteBtn);

        // Count label
        Label countLabel = new Label();
        countLabel.textProperty().bind(
            javafx.beans.binding.Bindings.createStringBinding(
                () -> "Total contacts: " + contacts.size(),
                contacts
            )
        );

        root.getChildren().addAll(
            new Label("Contact Manager"),
            table,
            inputBox,
            countLabel
        );

        Scene scene = new Scene(root, 600, 500);
        primaryStage.setTitle("Contact Manager");
        primaryStage.setScene(scene);
        primaryStage.show();
    }

    public static void main(String[] args) {
        launch(args);
    }
}
